Field(
        title=_("Edited part only (vibrato mode)"),
        description=_(
            "Input the edited part of pitch curve; default vibrato will be imported if not edited"
        ),
    )

Field(
        title=_("All removed"),
        description=_(
            "All notes will be set to 0 vibrato depth to ensure the output pitch curve is the same as input"
        ),
    )

Field(
        title=_("All kept"),
        description=_(
            "Keep all notes' default vibrato, but may cause inconsistent pitch curves"
        ),
    )

Field(
        title=_("Act on timeline"),
        description=_(
            'Shift the time axis for each line of lyrics, and keep the "offset" value in the metadata at 0.'
        ),
    )

Field(
        title=_("Act on metadata"),
        description=_(
            'Write the offset to the metadata "offset" without handling the lyrics time axis. Note that some players may not support the "offset" tag in the metadata, and choosing this option may cause the lyrics to display incorrectly.'
        ),
    )

Field(
